// TRF_NormalizeAndValidate - Gate de entrada (STRICT)
// v3.0 - Added media URL extraction for audio/image processing
const input = $json;
const body = input.body || input;
const headers = input.headers || {};

// === CONFIG ===
const WHITELIST = ['5593992166616', '5511999999999', '5593991234567', '5593984345505', '559398434550'];

// === HELPERS ===
function normalizePhone(raw) {
  if (!raw) return '';
  let digits = String(raw).replace(/\D/g, '');
  if (!digits.startsWith('55') && (digits.length === 10 || digits.length === 11)) {
    digits = '55' + digits;
  }
  if (digits.startsWith('55') && digits.length === 12) {
    digits = digits.slice(0, 4) + '9' + digits.slice(4);
  }
  if (digits.length > 13) {
    digits = digits.slice(0, 13);
  }
  return digits;
}

// === EXTRAÇÃO - Handle Z-API format AND test format ===
const zapiData = body.data || {};
const zapiKey = zapiData.key || {};
const zapiMessage = zapiData.message || {};

// Extract phone from remoteJid
const remoteJid = zapiKey.remoteJid || '';
const phoneFromJid = remoteJid.split('@')[0].replace('+', '');

// Extract message ID
const messageId = zapiKey.id || body.messageId || body.id?.id || `test_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

// Extract phone
const phone = normalizePhone(phoneFromJid || body.from_phone || body.phone || body.from);

// Extract text - try Z-API format first, then test format, then fallback
const text = zapiMessage.conversation || 
             zapiMessage.extendedTextMessage?.text || 
             body.message ||
             body.text?.message || 
             body.caption || 
             '';

// === MEDIA DETECTION ===
let mediaType = null;
let isMedia = false;
let mediaUrl = null;
let mediaCaption = null;

if (zapiMessage.audioMessage || body.audio) {
  mediaType = 'audio';
  isMedia = true;
  mediaUrl = zapiMessage.audioMessage?.url 
    || zapiMessage.audioMessage?.directPath
    || body.audio?.audioUrl 
    || body.audio?.url
    || body.audioUrl
    || null;
} else if (zapiMessage.imageMessage || body.image) {
  mediaType = 'image';
  isMedia = true;
  mediaUrl = zapiMessage.imageMessage?.url 
    || zapiMessage.imageMessage?.directPath
    || body.image?.imageUrl 
    || body.image?.url
    || body.imageUrl
    || null;
  mediaCaption = zapiMessage.imageMessage?.caption 
    || body.image?.caption 
    || body.caption
    || null;
} else if (zapiMessage.videoMessage || body.video) {
  mediaType = 'video';
  isMedia = true;
} else if (zapiMessage.documentMessage || zapiMessage.documentWithCaptionMessage || body.document) {
  mediaType = 'document';
  isMedia = true;
} else if (zapiMessage.stickerMessage || body.sticker) {
  mediaType = 'sticker';
  isMedia = true;
} else if (zapiMessage.contactMessage || zapiMessage.contactsArrayMessage) {
  mediaType = 'contact';
  isMedia = true;
} else if (zapiMessage.locationMessage || zapiMessage.liveLocationMessage) {
  mediaType = 'location';
  isMedia = true;
}

// Extract flags
const isGroup = remoteJid.includes('@g.us') || body.isGroup === true;
const fromMe = zapiKey.fromMe === true || body.fromMe === true;

// === REGRA DE AUTORIZAÇÃO ===
const isAuthorized = WHITELIST.includes(phone);

// Media messages should NOT be ignored
const shouldIgnore = !isAuthorized || isGroup || fromMe || (!text && !isMedia);

// === TRACE ===
const trace_id = `emii_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

// === IGNORE REASON ===
let ignoreReason = '';
if (!isAuthorized) ignoreReason = 'unauthorized_phone';
else if (isGroup) ignoreReason = 'is_group';
else if (fromMe) ignoreReason = 'from_me';
else if (!text && !isMedia) ignoreReason = 'empty_text';

return [{
  json: {
    provider_message_id: messageId,
    from_phone: phone,
    text_raw: text,
    is_group: isGroup,
    from_me: fromMe,
    is_media: isMedia,
    media_type: mediaType,
    media_url: mediaUrl,
    media_caption: mediaCaption,
    trace_id: trace_id,
    received_at: new Date().toISOString(),
    validation: {
      should_ignore: shouldIgnore,
      ignore_reason: ignoreReason,
      is_authorized: isAuthorized
    }
  }
}];

// Return ignored status (HTTP response)
const input = $('TRF_NormalizeAndValidate').item.json;
return [{
  json: {
    status: 'ignored',
    reason: input.validation.ignore_reason,
    trace_id: input.trace_id
  }
}];

// Return duplicate status (HTTP response)
const input = $('TRF_NormalizeAndValidate').item.json;
return [{
  json: {
    status: 'duplicate',
    trace_id: input.trace_id,
    provider_message_id: input.provider_message_id
  }
}];

// TRF_BuildEnvelope - Montar envelope completo
// v3.0 - Suporte robusto a áudio transcrito e imagem analisada
const normalized = $('TRF_NormalizeAndValidate').item.json;
const prefs = $('DB_FetchPrefs').all()[0]?.json || {};

// === DETERMINAR O TEXTO EFETIVO ===
// Para áudio/imagem, o texto foi injetado pelos nodes TRF_Inject*
// Para texto normal, vem direto do NormalizeAndValidate
// Precisamos tentar buscar de cada fonte possível

let effectiveText = '';

// Tentar pegar do TRF_InjectAudioText (se o fluxo passou por lá)
try {
  const audioData = $('TRF_InjectAudioText').item.json;
  if (audioData && audioData.text_raw) {
    effectiveText = audioData.text_raw;
  }
} catch(e) {
  // Node não executado nesta run, ignorar
}

// Tentar pegar do TRF_InjectImageText (se o fluxo passou por lá)
if (!effectiveText) {
  try {
    const imageData = $('TRF_InjectImageText').item.json;
    if (imageData && imageData.text_raw) {
      effectiveText = imageData.text_raw;
    }
  } catch(e) {
    // Node não executado nesta run, ignorar
  }
}

// Fallback: texto normal do NormalizeAndValidate
if (!effectiveText) {
  effectiveText = normalized.text_raw || '';
}

// Determinar tipo de mídia original
let originalMediaType = null;
try {
  const audioData = $('TRF_InjectAudioText').item.json;
  if (audioData?.original_media_type) originalMediaType = audioData.original_media_type;
} catch(e) {}
if (!originalMediaType) {
  try {
    const imageData = $('TRF_InjectImageText').item.json;
    if (imageData?.original_media_type) originalMediaType = imageData.original_media_type;
  } catch(e) {}
}

const envelope = {
  trace_id: normalized.trace_id,
  provider_message_id: normalized.provider_message_id,
  from_phone: normalized.from_phone,
  received_at: normalized.received_at,

  // === MENSAGEM DO USUÁRIO ===
  user_message: effectiveText,
  text_raw: effectiveText,

  // === MEDIA INFO ===
  original_media_type: originalMediaType,
  media_url: normalized.media_url || null,

  prefs: {
    lead_time_default_seconds: prefs.lead_time_default_seconds || 600,
    timezone: prefs.timezone || 'America/Belem'
  }
};

return [{ json: { envelope } }];

// Return accepted status (HTTP response)
const envelope = $('TRF_BuildEnvelope').item.json.envelope;
return [{
  json: {
    status: 'accepted',
    trace_id: envelope.trace_id,
    provider_message_id: envelope.provider_message_id
  }
}];

// TRF_PrepareMediaFallback - Prepare fallback response for unsupported media
const normalized = $('TRF_NormalizeAndValidate').item.json;
const mediaType = normalized.media_type;

const mediaLabels = {
  'audio': 'áudios',
  'image': 'imagens',
  'video': 'vídeos',
  'document': 'documentos',
  'sticker': 'figurinhas',
  'contact': 'contatos',
  'location': 'localizações'
};

const label = mediaLabels[mediaType] || 'esse tipo de mídia';

const fallbackText = `Oi Márcio! Ainda não consigo processar ${label}, mas estou evoluindo! 🚀 Por enquanto, me envia em texto que eu resolvo rapidinho. Como posso te ajudar?`;

// Format phone for Z-API
let toPhone = normalized.from_phone;
if (!toPhone.includes('@')) {
  toPhone = toPhone.replace(/[^0-9]/g, '') + '@s.whatsapp.net';
}

return [{
  json: {
    phone: toPhone,
    message: fallbackText,
    trace_id: normalized.trace_id,
    media_type: mediaType
  }
}];

// TRF_ReturnMediaFallback - Return after sending media fallback
const prepared = $('TRF_PrepareMediaFallback').item.json;
const zapiResp = $json;

return [{
  json: {
    status: 'media_fallback_sent',
    media_type: prepared.media_type,
    trace_id: prepared.trace_id,
    zapi_response: zapiResp
  }
}];

// TRF_InjectAudioText - Injeta transcrição do AssemblyAI no fluxo normal
const normalized = $('TRF_NormalizeAndValidate').item.json;
const transcriptResponse = $json;

// AssemblyAI retorna { text: "transcrição", status: "completed" }
const transcription = transcriptResponse.text || '';

if (!transcription) {
  return [{
    json: {
      ...normalized,
      text_raw: '[Áudio recebido mas não foi possível transcrever]',
      is_media: false,
      original_media_type: 'audio',
      media_transcription: null
    }
  }];
}

return [{
  json: {
    ...normalized,
    text_raw: transcription,
    user_message: transcription,
    is_media: false,
    original_media_type: 'audio',
    media_transcription: transcription
  }
}];

