// TRF_InjectImageText - Injeta descrição da Vision API no fluxo normal
const normalized = $('TRF_NormalizeAndValidate').item.json;
const visionResponse = $json;

// OpenRouter/GPT-4o Vision retorna em choices[0].message.content
const description = visionResponse.choices?.[0]?.message?.content || '';
const caption = normalized.media_caption || '';

let finalText = '';

if (description) {
  if (caption) {
    finalText = `[Imagem com legenda: "${caption}"]\n\nConteúdo da imagem: ${description}`;
  } else {
    finalText = `[Imagem recebida]\n\nConteúdo da imagem: ${description}`;
  }
} else {
  finalText = caption 
    ? `[Imagem com legenda: "${caption}"] - Não foi possível analisar o conteúdo visual.`
    : '[Imagem recebida mas não foi possível analisar]';
}

return [{
  json: {
    ...normalized,
    text_raw: finalText,
    user_message: finalText,
    is_media: false,
    original_media_type: 'image',
    media_description: description,
    media_caption: caption
  }
}];
